def task_status(self, req: dict[str, Any]) -> dict[str, Any]:
    job_id = self._safe_job_id(req.get("job_id"))
    requested_run_id = req.get("run_id")
    if requested_run_id is not None and (
        not isinstance(requested_run_id, str)
        or not re.fullmatch(r"[A-Za-z0-9._-]+", requested_run_id)
    ):
        raise GovernedError("Invalid run_id")
    include_result = bool(req.get("include_result", False))
    root = self.staging_root / job_id
    runs: list[dict[str, Any]] = []
    if root.is_dir():
        for run in sorted(
            p for p in root.iterdir()
            if p.is_dir() and p.name != "_background"
        ):
            state = None
            state_path = run / "run-state.json"
            if state_path.is_file():
                with contextlib.suppress(Exception):
                    state = load_json(state_path)
            runs.append({"run_id": run.name, "state": state})

    background_runs: list[dict[str, Any]] = []
    background_root = self._background_root(job_id)
    if background_root.is_dir():
        for run in sorted(p for p in background_root.iterdir() if p.is_dir()):
            state = None
            state_path = run / "run-state.json"
            if state_path.is_file():
                with contextlib.suppress(Exception):
                    state = load_json(state_path)
            pid_record = None
            pid_path = run / "worker-pid.json"
            if pid_path.is_file():
                with contextlib.suppress(Exception):
                    pid_record = load_json(pid_path)
            pid = (
                state.get("worker_pid")
                if isinstance(state, dict)
                else pid_record.get("worker_pid")
                if isinstance(pid_record, dict)
                else None
            )
            entry: dict[str, Any] = {
                "run_id": run.name,
                "state": state,
                "worker_alive": self._worker_alive(pid),
                "result_available": (run / "phase-result.json").is_file(),
                "error_available": (run / "phase-error.json").is_file(),
            }
            if include_result and (
                requested_run_id is None or requested_run_id == run.name
            ):
                result_path = run / "phase-result.json"
                error_path = run / "phase-error.json"
                if result_path.is_file():
                    with contextlib.suppress(Exception):
                        entry["result"] = load_json(result_path)
                if error_path.is_file():
                    with contextlib.suppress(Exception):
                        entry["error"] = load_json(error_path)
            background_runs.append(entry)

    selected: dict[str, Any] | None = None
    if requested_run_id is not None:
        for entry in [*runs, *background_runs]:
            if entry.get("run_id") == requested_run_id:
                selected = entry
                break
        if selected is None:
            raise GovernedError(
                f"Run not found for job {job_id}: {requested_run_id}"
            )

    return {
        "ok": True,
        "job_id": job_id,
        "job": self._load_job(job_id),
        "runs": runs,
        "background_runs": background_runs,
        "selected_run": selected,
    }

