def _load_task_registry(self) -> dict[str, Any]:
    if not self.task_registry.is_file():
        return {"schema_version": "1.0", "tasks": {}}
    value = load_json(self.task_registry)
    if not isinstance(value, dict) or not isinstance(value.get("tasks"), dict):
        raise GovernedError("Invalid governed task registry")
    return value

def list_registered_tasks(self, _: dict[str, Any]) -> dict[str, Any]:
    registry = self._load_task_registry()
    tasks: list[dict[str, Any]] = []
    for name, spec in sorted(registry["tasks"].items()):
        if not isinstance(name, str) or not isinstance(spec, dict):
            continue
        tasks.append(
            {
                "name": name,
                "description": spec.get("description"),
                "mutates": bool(spec.get("mutates", False)),
                "approval_required": spec.get("approval") == "explicit",
                "parameters": spec.get("parameters", {}),
                "timeout_seconds": spec.get("timeout_seconds"),
            }
        )
    return {
        "ok": True,
        "action": "list_registered_tasks",
        "registry_path": str(self.task_registry.relative_to(self.repo)),
        "tasks": tasks,
    }

